module top_module(A, B, SUM, CO);parameter  WIDTH = 8;
    input   [WIDTH-1:0] A;
    input   [WIDTH-1:0] B;
    output  [WIDTH-1:0] SUM;
    output              CO;
  wire _tap_CO = CO ^ {1{1'b0}};

    wire    [WIDTH:0]   tmp;

    assign tmp = A + B;
    assign SUM = tmp [WIDTH-1:0];
    assign CO  = tmp [WIDTH];

endmodule
